#include <bits/stdc++.h>
using namespace std;
#define int long long
const int mod = 1e9 + 7; int solve() { __int128_t n = 0; string n_; cin >> n_; for (char c : n_) { n = 10 * n + (c - '0'); } __int128_t l = 1, r = __int128_t(1) << 65, kesimo = l; auto to_string = [&](__int128_t a) { string Res = ""; while (a) { Res.push_back(char('0' + (a % 10))); a /= 10; } reverse(Res.begin(), Res.end()); return Res; }; auto cont_zero = [&](__int128_t a) { vector dp(20, vector(20, vector(2, vector<__int128_t>(2, -1)))); string S = to_string(a); function<__int128_t(int, int, int, int)> f = [&](int pos, int tight, int zero_e, int tem_zero) -> __int128_t { if (pos == S.size()) return tem_zero;	auto& res = dp[pos][tight][zero_e][tem_zero]; if (res != -1) return res; res = 0; int teto = tight ? S[pos] - '0' : 9; for (int i = 0; i <= teto; i++) { res += f(pos + 1, tight and (i == teto), zero_e and (i == 0), tem_zero or (!zero_e and !i)); } return res; }; return f(0, 1, 1, 0); };  while (l <= r) { __int128_t mid = l + (r - l) / 2; if (mid - cont_zero(mid) >= n) { r = mid - 1; kesimo = mid; } else { l = mid + 1; } }  string S = to_string(kesimo); int tot = 0; for (int dig = 1; dig <= 9; dig++) { vector dp(20, vector(2, vector(2, vector(2, vector<__int128_t>(20, -1))))); function<__int128_t(int, int, int, int, int)> f = [&](int pos, int tight, int zero_e, int tem_zero, int cont) -> __int128_t { if (pos == S.size()) return !tem_zero * cont;	auto& res = dp[pos][tight][zero_e][tem_zero][cont]; if (res != -1) return res; res = 0; int teto = tight ? S[pos] - '0' : 9; for (int i = 0; i <= teto; i++) { res += f(pos + 1, tight and (i == teto), zero_e and (i == 0), tem_zero or (!zero_e and i == 0), cont + (i == dig)); } return res; }; tot = (tot + dig * f(0, 1, 1, 0, 0)) % mod; } cout << tot << "\n"; return(0); } signed main() { ios_base::sync_with_stdio(0);cin.tie(0);; solve(); return(0); }
